mapper.select:
SELECT ua.*
FROM user_auth ua
         INNER JOIN `user` u ON ua.user_id = u.id
WHERE ua.account = #{account}
  AND ua.role_id = #{roleId}
  AND u.institution_id = #{institutionId}

SELECT COUNT(1)
FROM user_auth ua
         INNER JOIN user u ON ua.user_id = u.id
WHERE u.institution_id = #{institutionId}
  AND ua.account = #{account}
  AND ua.role_id = #{roleId}
LIMIT 1
